import { $_ } from '@aegis-framework/artemis';
import type { Component } from '@aegis-framework/pandora';
import type { Configuration, MonogatariEngine } from './types';


type Constructor<T = object> = new (...args: any[]) => T;

type PandoraComponentConstructor = Constructor<Component> & {
	tag: string;
};

/**
 * Mixin containing shared functionality between Component and ShadowComponent.
 * This reduces code duplication by extracting the common Monogatari-specific methods.
 *
 * Usage:
 *   class Component extends applyComponentMixin(PandoraComponent) { ... }
 *   class ShadowComponent extends applyComponentMixin(PandoraShadowComponent) { ... }
 *
 * @param Base - The base class to extend (PandoraComponent or PandoraShadowComponent)
 * @returns The mixed class with Monogatari-specific functionality
 */
export function applyComponentMixin<TBase extends PandoraComponentConstructor> (Base: TBase) {

	class MonogatariComponent extends Base {
		/**
		 * Marks the component as experimental
		 */
		static _experimental: boolean = false;

		/**
		 * Component-specific configuration object.
		 *
		 * IMPORTANT: Subclasses should declare their own `static _configuration = {}`
		 * to avoid sharing state with other components.
		 */
		static _configuration: Configuration = {};

		static _priority: number = 0;

		/**
		 * Reference to the Monogatari engine (set by engine on registration)
		 */
		static engine: MonogatariEngine;

		/**
		 * Parent component reference
		 */
		_parent?: Component;


		constructor (...args: any[]) {
			super(...args);
		}

		/**
		 * Access or update the configuration object
		 */
		static configuration (object: string | Configuration | null = null): Configuration | unknown {
			if (object !== null) {
				if (typeof object === 'string') {
					return this._configuration[object];
				} else {
					this._configuration = Object.assign({}, this._configuration, object);
				}
			} else {
				return this._configuration;
			}
		}

		static all (): ReturnType<typeof $_> {
			return $_(this.tag);
		}

		static get (id: string): ReturnType<typeof $_> {
			return $_(`${this.tag} [data-instance="${id}"]`);
		}

		/**
		 * Event listener for when the game starts
		 */
		static onStart (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Event listener for when a game is loaded
		 */
		static onLoad (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Setup step of the Mounting cycle
		 */
		static setup (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Check if it's ok to proceed - aggregates from all instances
		 */
		static shouldProceed (): Promise<unknown[]> {
			const promises: Promise<void>[] = [];

			this.instances((instance: any) => {
				promises.push(instance.shouldProceed());
			});
			return Promise.all(promises);
		}

		/**
		 * Respond to game proceeding - aggregates from all instances
		 */
		static willProceed (): Promise<unknown[]> {
			const promises: Promise<void>[] = [];

			this.instances((instance: any) => {
				promises.push(instance.willProceed());
			});
			return Promise.all(promises);
		}

		/**
		 * Check if it's ok to go back - aggregates from all instances
		 */
		static shouldRollback (): Promise<unknown[]> {
			const promises: Promise<void>[] = [];

			this.instances((instance: any) => {
				promises.push(instance.shouldRollback());
			});
			return Promise.all(promises);
		}

		/**
		 * Respond to game reverting - aggregates from all instances
		 */
		static willRollback (): Promise<unknown[]> {
			const promises: Promise<void>[] = [];

			this.instances((instance: any) => {
				promises.push(instance.willRollback());
			});
			return Promise.all(promises);
		}

		/**
		 * Bind step of the Mounting cycle
		 */
		static bind (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Init step of the Mounting cycle
		 */
		static init (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Event listener for when a game is saved
		 */
		static onSave (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Reset component state - aggregates from all instances
		 */
		static onReset (): Promise<unknown[]> {
			const promises: Promise<void>[] = [];

			this.instances((instance: any) => {
				promises.push(instance.onReset());
			});
			return Promise.all(promises);
		}

		/**
		 * Get all instances of this component, optionally iterating with callback
		 */

		static instances (callback: ((instance: any) => void) | null = null): ReturnType<typeof $_> {
			if (typeof callback === 'function') {

				return $_(this.tag).each(callback as any);
			}
			return $_(this.tag);
		}

		// =========================================
		// Instance Methods
		// =========================================

		/**
		 * Reset this instance's state
		 */
		onReset (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Returns this component's element as an Artemis DOM instance
		 */
		element (): ReturnType<typeof $_> {
			return $_(this);
		}

		/**
		 * Remove this component from the DOM
		 */
		override remove (): void {
			this.parentNode?.removeChild(this);
		}

		/**
		 * Find an instance by ID within this component type
		 */
		instance (id: string): ReturnType<typeof $_> {
			const ctor = this.constructor as typeof MonogatariComponent;
			return $_(`${ctor.tag}[data-${ctor.name.toLowerCase()}="${id}"`);
		}

		/**
		 * Get or set the parent component
		 */
		parent (component?: Component): Component | undefined | void {
			if (typeof component !== 'undefined') {
				this._parent = component;
			} else {
				return this._parent;
			}
		}

		/**
		 * Get the engine reference
		 */
		get engine (): MonogatariEngine {
			return (this.constructor as typeof MonogatariComponent).engine;
		}

		set engine (_value: MonogatariEngine) {
			throw new Error('Component engine reference is hold at static level and cannot be modified.');
		}

		/**
		 * Check if it's ok to proceed
		 */
		shouldProceed (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Respond to game proceeding
		 */
		willProceed (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Check if it's ok to go back
		 */
		shouldRollback (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Respond to game reverting
		 */
		willRollback (): Promise<void> {
			return Promise.resolve();
		}

		/**
		 * Called when the component is connected to the DOM
		 */
		connectedCallback (): Promise<void> {
			// Always add the animated class for all the components
      // TODO: Let's be honest, this is stupid.
			this.classList.add('animated');

			const result = super.connectedCallback();
			return result instanceof Promise ? result : Promise.resolve();
		}
	}

	return MonogatariComponent;
}
