import type {
  Configuration,
  ActionApplyResult,
  ActionRevertResult,
  ActionRunContext,
  ActionRevertContext,
  SaveSlot,
  MonogatariEngine,
} from './types';

/**
 * An action describes the functionality for a Monogatari statement. When Monogatari
 * reads a part of the script (a statement), it will look for an action that matches
 * the statement and run it.
 *
 * The life cycle of an action is divided in three parts: Mounting, Application
 * and Reverting.
 *
 * The mounting cycle has 3 steps:
 * 1. Setup - Set up everything needed for working (variables, HTML, etc.)
 * 2. Bind - Bind event listeners and perform DOM operations
 * 3. Init - Final operations after setup and binding
 *
 * The Application cycle has 3 steps:
 * 1. Will Apply - Operations before application
 * 2. Apply - Core logic of the action
 * 3. Did Apply - Cleanup after application
 *
 * The Revert cycle mirrors Application:
 * 1. Will Revert - Operations before reversion
 * 2. Revert - Core reversion logic
 * 3. Did Revert - Cleanup after reversion
 */
class Action {
	/**
	 * Marks the action as experimental
	 */
	static _experimental: boolean = false;

	/**
	 * Action-specific configuration object
	 */
	static _configuration: Configuration = {};

	/**
	 * Unique identifier for the action
	 */
	static id: string = 'Action';

	/**
	 * Loading order for sorting action execution on game load
	 */
	static loadingOrder: number = 0;

	/**
	 * Reference to the Monogatari engine (set by engine on registration)
	 */
	static engine: MonogatariEngine;

	/**
	 * The original statement this action was instantiated with
	 */
	protected _statement: string | string[] | Record<string, unknown> | ((...args: unknown[]) => unknown) | undefined;

	/**
	 * Current cycle: 'Application' or 'Revert'
	 */
	protected _cycle: string | undefined;

	/**
	 * Extra context passed to the action
	 */
	protected _extras: Record<string, unknown> | undefined;

	/**
	 * Context reference (usually the Monogatari class)
	 */
	context: MonogatariEngine | undefined;

	/**
	 * Access or update the configuration object
	 */
	static configuration (object: string | Configuration | null = null): Configuration | unknown {
		if (object !== null) {
			if (typeof object === 'string') {
				return this._configuration[object];
			} else {
				this._configuration = Object.assign({}, this._configuration, object);
			}
		} else {
			return this._configuration;
		}
	}

	/**
	 * Check if it's ok to proceed to the next statement
	 */
	static shouldProceed (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Respond to the game proceeding
	 */
	static willProceed (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Check if it's ok to go back
	 */
	static shouldRollback (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Respond to the game reverting
	 */
	static willRollback (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Event listener for when the game starts
	 */
	static onStart (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Event listener for when a game is loaded
	 */
	static onLoad (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Event listener for when a game is saved
	 */
	static onSave (_slot?: SaveSlot): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Reset action state when game ends or new game loads
	 */
	static reset (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Setup step of the Mounting cycle
	 */
	static setup (_selector?: string): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Bind step of the Mounting cycle
	 */
	static bind (_selector?: string): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Init step of the Mounting cycle
	 */
	static init (_selector?: string): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Check if the action matches a statement
	 */
	static match (_statement: unknown): boolean {
		return false;
	}

	/**
	 * Check if the action matches a string statement
	 */
	static matchString (_statement: string[]): boolean {
		return false;
	}

	/**
	 * Check if the action matches an object statement
	 */
	static matchObject (_statement: Record<string, unknown>): boolean {
		return false;
	}

	/**
	 * Called before run
	 */
	static beforeRun (_context: ActionRunContext): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Called before revert
	 */
	static beforeRevert (_context: ActionRevertContext): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Called after run
	 */
	static afterRun (_context: ActionRunContext): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Called after revert
	 */
	static afterRevert (_context: ActionRevertContext): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Constructor - receives the matched statement
	 */
	constructor (_statement?: string[] | Record<string, unknown>) {
		// Statement is set via _setStatement
	}

	/**
	 * Get the engine reference
	 */
	get engine (): MonogatariEngine {
		return (this.constructor as typeof Action).engine;
	}

	set engine (_value: MonogatariEngine) {
		throw new Error('Component engine reference is hold at static level and cannot be modified.');
	}

	/**
	 * Set the context (usually Monogatari class)
	 */
	setContext (context: MonogatariEngine): void {
		this.context = context;
	}

	/**
	 * Set the original statement
	 */
	_setStatement (statement: string | Record<string, unknown> | ((...args: unknown[]) => unknown)): void {
		this._statement = statement;
	}

	/**
	 * Set the current cycle
	 */
	_setCycle (cycle: string): void {
		this._cycle = cycle;
	}

	/**
	 * Set extra context
	 */
	setExtras (extras: Record<string, unknown>): void {
		this._extras = extras;
	}

	/**
	 * Called before apply - can reject to interrupt
	 */
	willApply (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Core application logic
	 */
	apply (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Called after apply - returns whether to advance
	 */
	didApply (): Promise<ActionApplyResult> {
		return Promise.resolve({
			advance: false
		});
	}

	/**
	 * Interrupt the action
	 */
	interrupt (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Called before revert - can reject to interrupt
	 */
	willRevert (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Core reversion logic
	 */
	revert (): Promise<void> {
		return Promise.resolve();
	}

	/**
	 * Called after revert - returns whether to advance and step
	 */
	didRevert (): Promise<ActionRevertResult> {
		return Promise.resolve({
			advance: false,
			step: true
		});
	}
}

export { Action };

